import React, { useState, useEffect } from 'react';
import { View, Text, Button } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import Biometrics from 'react-native-biometrics';

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  useEffect(() => {
    checkBiometricSupport();
  }, []);

  const checkBiometricSupport = async () => {
    try {
      const isSupported = await Biometrics.isEnrolled(Biometrics.Type.FACE_ID);
      if (isSupported) {
        await AsyncStorage.getItem('biometricAuth').then((value) => {
          if (value === 'true') {
            setIsAuthenticated(true);
          }
        });
      } else {
        console.log('Biometric authentication not supported');
      }
    } catch (error) {
      console.error(error);
    }
  };

  const handleLogin = async () => {
    try {
      const isSupported = await Biometrics.isEnrolled(Biometrics.Type.FACE_ID);
      if (isSupported) {
        const result = await Biometrics.authenticate({
          promptMessage: 'Please authenticate with Face ID',
          biometryType: Biometrics.Type.FACE_ID,
        });
        if (result.success) {
          setIsAuthenticated(true);
          AsyncStorage.setItem('biometricAuth', 'true');
        } else {
          console.log('Biometric authentication failed');
        }
      } else {
        console.log('Biometric authentication not supported');
      }
    } catch (error) {
      console.error(error);
    }
  };

  const handlePasswordLogin = async () => {
    try {
      // Implement password login logic here
      setIsAuthenticated(true);
      AsyncStorage.setItem('biometricAuth', 'false');
    } catch (error) {
      console.error(error);
    }
  };

  if (isAuthenticated) {
    return (
      <View>
        <Text>Authenticated</Text>
      </View>
    );
  }

  return (
    <View>
      <Button title="Login with Biometrics" onPress={handleLogin} />
      <Button title="Login with Password" onPress={handlePasswordLogin} />
    </View>
  );
};

export default App;